#!/usr/bin/env bash
# design-system.sh — 设计系统搭建（design system） SOP walkthrough for 产品设计 / UX 设计.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="产品设计 / UX 设计"
WORKFLOW="设计系统搭建（design system）"

usage() {
  cat <<EOF
design-system.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./design-system.sh             # interactive
  ./design-system.sh --dry-run
  ./design-system.sh --json
  ./design-system.sh --explain
  ./design-system.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "设计系统搭建（design system）" 工作流。

一句话: 从「多产品/多人界面不一致、组件不复用、改一处要改十处」到「一套 token + 组件库 + 文档 + 治理流程」，让一致性可规模化。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 行为 > 自陈（You are not the user）: 设计决策必须基于**观察到的真实行为**，而非设计师/利益相关者的意见、也不是用户口头说的偏好——"你不是用户"，"opinions are not data"。 (figures: Krug / H
  • 认知负荷最小化（Don't Make Me Think）: 好设计让"正确操作显而易见"，把思考成本从用户身上移走——识别（recognition）优于回忆（recall），扫读优于阅读，满意即止（satisficing）。 (figures: Krug / 

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**接口审计 / 库存（interface inventory）**: 截图现有所有 UI 元素，找出有多少种按钮/输入框等，暴露不一致。跳过→在没摸清现状的地基上盖系统，漏掉真实用例。 (evidence: [T03-S012])"
  "**定 token（subatomic）**: 抽颜色/间距/字号/圆角等为变量，作单一真值源。跳过→组件硬编码值，无法全局换肤/改版。 (evidence: [T03-S012, T03-S013])"
  "**按原子层级建组件（atomic）**: atoms→molecules→organisms→templates→pages，从小到大组合。跳过→直接做大组件，复用性差、难维护。 (evidence: [T03-S012])"
  "**写文档 + 用法规范**: 每个组件给「何时用/不用/可访问性」。跳过→有库无文档，团队各用各的，系统形同虚设。 (evidence: [T03-S013])"
  "**建治理 + 贡献流程（生态）**: 谁维护、怎么提需求、怎么版本化、设计↔代码怎么同步。跳过→系统上线即腐烂，分叉成多套。 (evidence: [T03-S013])"
)
declare -a FAILURE_MODES=(
  "当成「组件库」而非「生态」: 只建库不建治理/流程，系统上线即腐烂分叉。**第一天就定维护人+贡献流程+版本策略，否则别启动。** (evidence: [T03-S013])"
  "一次造大而全: 没用例支撑就建上百组件。**从审计出的真实高频用例起步，一个能用的小系统再演化。** (evidence: [T03-S013, T03-S012])"
  "设计与代码 token 不同步: Figma 一套、代码一套，越走越偏。**用 Tokens Studio/Supernova 建单一真值源自动同步。** (evidence: [T03-S013])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "design-system-walkthrough"
fi
